import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import { adminService } from '../../services/api';

export default function AdminRoundScheduling({ appId, onBack }) {
  const [view, setView] = useState(null);  // null, scheduling, results
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState(null);
  const [selectedRound, setSelectedRound] = useState(null);
  const [scheduling, setScheduling] = useState({
    roundNumber: 1,
    roundType: 'Aptitude',
    scheduledDate: '',
    scheduledTime: '',
    location: '',
    interviewMode: 'Online',
  });
  const [result, setResult] = useState({
    result: 'PASS',
    score: 0,
    notes: '',
    feedback: '',
  });

  useEffect(() => {
    fetchData();
  }, [appId]);

  const fetchData = async () => {
    setLoading(true);
    try {
      const { data: viewData } = await adminService.getRoundScheduling(appId);
      setData(viewData);
      setView(viewData.rounds.length === 0 ? 'scheduling' : null);
    } catch {
      toast.error('Failed to load round data.');
    } finally {
      setLoading(false);
    }
  };

  const handleScheduleRound = async e => {
    e.preventDefault();
    if (!scheduling.scheduledDate || !scheduling.scheduledTime) {
      toast.error('Please fill in date and time.');
      return;
    }
    try {
      await adminService.scheduleRound(appId, scheduling);
      toast.success(`Round ${scheduling.roundNumber} scheduled!`);
      setScheduling({
        roundNumber: (scheduling.roundNumber % data.numberOfRounds) + 1,
        roundType: 'Aptitude',
        scheduledDate: '',
        scheduledTime: '',
        location: '',
        interviewMode: 'Online',
      });
      fetchData();
    } catch {
      toast.error('Failed to schedule round.');
    }
  };

  const handleRecordResult = async e => {
    e.preventDefault();
    if (!selectedRound) return;
    try {
      await adminService.recordRoundResult(appId, selectedRound.id, result);
      toast.success('Round result recorded!');
      setSelectedRound(null);
      setResult({ result: 'PASS', score: 0, notes: '', feedback: '' });
      fetchData();
    } catch {
      toast.error('Failed to record result.');
    }
  };

  if (loading) {
    return (
      <div style={{ padding: '20px', textAlign: 'center', color: 'var(--gray-400)' }}>
        Loading round data...
      </div>
    );
  }

  if (!data) {
    return (
      <div style={{ padding: '20px', textAlign: 'center', color: 'var(--gray-400)' }}>
        No data available.
      </div>
    );
  }

  return (
    <div>
      <div style={{
        display: 'flex', justifyContent: 'space-between', alignItems: 'center',
        marginBottom: 20, paddingBottom: 16, borderBottom: '1px solid var(--gray-200)'
      }}>
        <div>
          <h3 style={{ margin: 0, fontSize: 18, fontWeight: 600, color: 'var(--text)' }}>
            Round Scheduling
          </h3>
          <p style={{ margin: '4px 0 0 0', fontSize: 13, color: 'var(--gray-400)' }}>
            {data.studentName} - {data.jobTitle}
          </p>
        </div>
        <button onClick={onBack} style={{
          background: 'none', border: 'none', fontSize: 20, color: 'var(--gray-400)',
          cursor: 'pointer'
        }}>×</button>
      </div>

      <div style={{
        display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(120px, 1fr))',
        gap: 12, marginBottom: 24
      }}>
        {Array.from({ length: data.numberOfRounds }, (_, i) => {
          const round = data.rounds[i];
          const status = round ? round.status : 'NOT_SCHEDULED';
          const color = status === 'SCHEDULED' ? 'var(--warning)' : status === 'COMPLETED' ? 'var(--success)' : 'var(--gray-300)';
          return (
            <div key={i+1} style={{
              padding: 12, background: color, color: 'white', borderRadius: 8,
              textAlign: 'center', fontWeight: 600, fontSize: 14, cursor: 'pointer'
            }} onClick={() => round && setSelectedRound(round)}>
              Round {i+1}
              <br />
              <span style={{ fontSize: 11, opacity: 0.8 }}>{status}</span>
            </div>
          );
        })}
      </div>

      {/* Current Round Display */}
      {view === null && data.rounds.length > 0 && (
        <div style={{ marginBottom: 24 }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
            {data.rounds.map(r => (
              <div key={r.id} style={{
                padding: 16, background: 'var(--gray-50)', borderRadius: 8,
                border: '1px solid var(--gray-200)'
              }}>
                <div style={{ fontSize: 14, fontWeight: 600, color: 'var(--text)', marginBottom: 8 }}>
                  Round {r.roundNumber} - {r.roundType}
                </div>
                <div style={{ fontSize: 12, color: 'var(--gray-400)', marginBottom: 4 }}>
                  Date: {r.scheduledDate || '—'} | Time: {r.scheduledTime || '—'}
                </div>
                <div style={{ fontSize: 12, color: 'var(--gray-400)', marginBottom: 8 }}>
                  Mode: {r.interviewMode || '—'} | Location: {r.location || '—'}
                </div>
                <div style={{
                  display: 'inline-block', padding: '4px 12px', borderRadius: 4,
                  fontSize: 11, fontWeight: 600,
                  background: r.status === 'COMPLETED' ? 'var(--success)' : 'var(--warning)',
                  color: 'white', marginBottom: 8
                }}>
                  {r.status}
                </div>
                {r.status === 'COMPLETED' && (
                  <div style={{ fontSize: 12, marginTop: 8, paddingTop: 8, borderTop: '1px solid var(--gray-200)' }}>
                    <div><strong>Result:</strong> {r.result}</div>
                    <div><strong>Score:</strong> {r.score}</div>
                    {r.feedback && <div style={{ marginTop: 4, color: 'var(--gray-600)' }}>{r.feedback}</div>}
                  </div>
                )}
                {r.status === 'SCHEDULED' && (
                  <button className="btn btn-sm btn-primary" onClick={() => setSelectedRound(r)}>
                    Record Result
                  </button>
                )}
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Schedule New Round */}
      {view === 'scheduling' || (view === null && data.rounds.length < data.numberOfRounds) && (
        <div style={{
          padding: 16, background: 'var(--gray-50)', borderRadius: 8,
          border: '1px solid var(--gray-200)', marginBottom: 24
        }}>
          <h4 style={{ margin: '0 0 16px 0', color: 'var(--text)' }}>
            Schedule Round {data.rounds.length + 1}
          </h4>
          <form onSubmit={handleScheduleRound}>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 12 }}>
              <div>
                <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)' }}>Round Type</label>
                <select value={scheduling.roundType} onChange={e => setScheduling(p => ({ ...p, roundType: e.target.value }))}>
                  <option>Aptitude</option>
                  <option>Technical Interview</option>
                  <option>Coding</option>
                  <option>Managerial Group Discussion</option>
                  <option>HR Round</option>
                  <option>Final Decision</option>
                </select>
              </div>
              <div>
                <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)' }}>Date</label>
                <input type="date" required value={scheduling.scheduledDate} onChange={e => setScheduling(p => ({ ...p, scheduledDate: e.target.value }))} />
              </div>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 12 }}>
              <div>
                <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)' }}>Time</label>
                <input type="time" required value={scheduling.scheduledTime} onChange={e => setScheduling(p => ({ ...p, scheduledTime: e.target.value }))} />
              </div>
              <div>
                <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)' }}>Interview Mode</label>
                <select value={scheduling.interviewMode} onChange={e => setScheduling(p => ({ ...p, interviewMode: e.target.value }))}>
                  <option>Online</option>
                  <option>In-person</option>
                  <option>Hybrid</option>
                </select>
              </div>
            </div>
            <button type="submit" className="btn btn-primary">Schedule Round</button>
          </form>
        </div>
      )}

      {/* Record Result Modal */}
      {selectedRound && selectedRound.status === 'SCHEDULED' && (
        <div style={{
          position: 'fixed', top: 0, left: 0, right: 0, bottom: 0,
          background: 'rgba(0,0,0,0.5)', display: 'flex', alignItems: 'center', justifyContent: 'center',
          zIndex: 1000
        }} onClick={() => setSelectedRound(null)}>
          <div style={{
            background: 'white', borderRadius: 12, padding: 24, maxWidth: 500,
            boxShadow: '0 10px 40px rgba(0,0,0,0.2)'
          }} onClick={e => e.stopPropagation()}>
            <h3 style={{ margin: '0 0 16px 0', color: 'var(--text)' }}>
              Record Result - Round {selectedRound.roundNumber}
            </h3>
            <form onSubmit={handleRecordResult}>
              <div style={{ marginBottom: 16 }}>
                <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)' }}>Result</label>
                <select value={result.result} onChange={e => setResult(p => ({ ...p, result: e.target.value }))}>
                  <option value="PASS">Pass</option>
                  <option value="FAIL">Fail</option>
                </select>
              </div>
              <div style={{ marginBottom: 16 }}>
                <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)' }}>Score</label>
                <input type="number" min="0" max="100" value={result.score} onChange={e => setResult(p => ({ ...p, score: parseInt(e.target.value) }))} />
              </div>
              <div style={{ marginBottom: 16 }}>
                <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)' }}>Notes</label>
                <textarea rows={3} placeholder="Internal notes..." value={result.notes} onChange={e => setResult(p => ({ ...p, notes: e.target.value }))} />
              </div>
              <div style={{ marginBottom: 16 }}>
                <label style={{ fontSize: 12, fontWeight: 600, color: 'var(--gray-400)' }}>Feedback (for candidate)</label>
                <textarea rows={3} placeholder="Feedback to share with candidate..." value={result.feedback} onChange={e => setResult(p => ({ ...p, feedback: e.target.value }))} />
              </div>
              <div style={{ display: 'flex', gap: 8 }}>
                <button type="button" className="btn btn-outline" onClick={() => setSelectedRound(null)}>Cancel</button>
                <button type="submit" className="btn btn-success">Submit Result</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
